CREATE TABLE IF NOT EXISTS posts (id INT UNSIGNED NOT NULL AUTO_INCREMENT, user_id INT UNSIGNED NOT NULL, type VARCHAR(20) NOT NULL DEFAULT 'text', content TEXT, media_file VARCHAR(255) DEFAULT NULL, video_url VARCHAR(500) DEFAULT NULL, announcement_subtype VARCHAR(30) DEFAULT NULL, reactions_count INT UNSIGNED NOT NULL DEFAULT 0, comments_count INT UNSIGNED NOT NULL DEFAULT 0, created_at DATETIME DEFAULT NULL, updated_at DATETIME DEFAULT NULL, PRIMARY KEY (id), KEY user_id (user_id), KEY created_at (created_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8; CREATE TABLE IF NOT EXISTS post_reactions (id INT UNSIGNED NOT NULL AUTO_INCREMENT, post_id INT UNSIGNED NOT NULL, user_id INT UNSIGNED NOT NULL, reaction_type VARCHAR(20) NOT NULL DEFAULT 'like', created_at DATETIME DEFAULT NULL, PRIMARY KEY (id), UNIQUE KEY post_user (post_id,user_id), KEY post_id (post_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8; CREATE TABLE IF NOT EXISTS post_comments (id INT UNSIGNED NOT NULL AUTO_INCREMENT, post_id INT UNSIGNED NOT NULL, user_id INT UNSIGNED NOT NULL, content TEXT NOT NULL, created_at DATETIME DEFAULT NULL, updated_at DATETIME DEFAULT NULL, PRIMARY KEY (id), KEY post_id (post_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8;
